definition.script:
pipeline {
  agent any

  parameters {
    string(name: 'BRANCH', defaultValue: '{{branch}}')
  }

  stages {
    stage('Clone') {
      steps {
        git branch: params.BRANCH, url: '{{repo_url}}'
      }
    }

    stage('Install') {
      steps {
        bat '{{install_command}}'
      }
    }

    stage('Build') {
      steps {
        bat '{{build_command}}'
      }
    }

    stage('Test') {
      steps {
        bat '{{test_command}}'
      }
    }
  }
}
